import{_ as a,o as i,c as t,aq as l}from"./chunks/framework.DLfWLF6u.js";const u=JSON.parse('{"title":"4 Skills I’m Learning that AI Can’t Replace (backed by data)","description":"","frontmatter":{},"headers":[],"relativePath":"AI/JeffSu/4-skills-im-learning-that-ai-cant-replace.md","filePath":"AI/JeffSu/4-skills-im-learning-that-ai-cant-replace.md","lastUpdated":1772204080000}'),n={name:"AI/JeffSu/4-skills-im-learning-that-ai-cant-replace.md"};function r(o,e,s,c,d,h){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="_4-skills-i-m-learning-that-ai-can-t-replace-backed-by-data" tabindex="-1">4 Skills I’m Learning that AI Can’t Replace (backed by data) <a class="header-anchor" href="#_4-skills-i-m-learning-that-ai-can-t-replace-backed-by-data" aria-label="Permalink to “4 Skills I’m Learning that AI Can’t Replace (backed by data)”">​</a></h1><h2 id="video-summary-english" tabindex="-1">Video Summary (English) <a class="header-anchor" href="#video-summary-english" aria-label="Permalink to “Video Summary (English)”">​</a></h2><ul><li><p>The Cockpit Rule: Learn to decide when to use AI based on the task&#39;s complexity and risk.</p><ul><li>Autopilot: Delegate simple, low-risk tasks entirely to AI.</li><li>Collaboration: Work iteratively with AI for tasks requiring your domain expertise.</li><li>Manual: Do the work yourself when the AI lacks specific context or the risk of failure is too high.</li></ul></li><li><p>Build the Rails: Your competitive advantage is no longer doing the work, but designing the process. Break down your recurring tasks into steps and create structured workflows so AI can seamlessly do the heavy lifting for you.</p></li><li><p>Storytelling Mode: In an AI world, basic information is a commodity. While AI is great at gathering data, humans excel at giving it meaning. Learn to use frameworks like &quot;And, But, Therefore&quot; to turn dry facts into engaging stories that move people.</p></li><li><p>Manual Override: Intentionally choose not to use AI for certain cognitive tasks so your critical thinking doesn&#39;t degrade. Always think first before prompting, and actively question or verify AI outputs rather than accepting them blindly.</p></li></ul><h2 id="视频总结-chinese" tabindex="-1">视频总结 (Chinese) <a class="header-anchor" href="#视频总结-chinese" aria-label="Permalink to “视频总结 (Chinese)”">​</a></h2><ul><li><p>驾驶舱法则 (The Cockpit Rule)：学会根据任务的复杂度和风险，来判断什么时候该用 AI。</p><ul><li>自动驾驶模式 (Autopilot)：把简单、低风险的任务全权交给 AI 去做。</li><li>协作模式 (Collaboration)：如果是需要你专业领域知识的任务，就通过不断与 AI 交互来共同完成。</li><li>手动模式 (Manual)：当 AI 缺乏具体上下文，或者失败风险太高时，你需要亲自动手。</li></ul></li><li><p>铺设轨道 (Build the Rails)：你现在的核心竞争力不再是“做具体的工作”，而是“设计流程”。把你重复性的任务拆解成一步步的操作，搭建起结构化的工作流，这样 AI 就能顺畅地帮你处理那些繁重费力的活儿。</p></li><li><p>讲故事的能力 (Storytelling Mode)：在一个充满 AI 的世界里，基础信息成了廉价商品。虽然 AI 很擅长收集数据，但人类最擅长赋予数据意义。去学习如何运用像 &quot;And, But, Therefore&quot; 这样的框架，把干巴巴的事实变成能打动人心的故事。</p></li><li><p>刻意的手动干预 (Manual Override)：为了不让你的批判性思维退化，对于某些认知任务，你要刻意选择“不用 AI”。在给出任何指令提示前自己先想一想，主动去质疑和验证 AI 给出的结果，而不是盲目接受。</p></li></ul><hr><p>以上是我用antigravity的workflow完成的一个视频总结文章.旨在完成一个过程:看视频 -&gt; 英文总结 -&gt; 中文总结 -&gt; 作为文章发布上来.<br> 不过看来,任重道远.这翻译的是什么东西?!?!总结是总结出来了,但你看看这是人话吗?(好像也确实不是人写出来的) // polish了一下,勉强看得过去了.不得不说,workflow真好玩.</p>',7)])])}const g=a(n,[["render",r]]);export{u as __pageData,g as default};
